9	class ec_pve_batch_t {
10	 public:
11	  explicit ec_pve_batch_t(int batch_count) : n(batch_count), rows(kappa) {
12	    cb_assert(batch_count > 0 && batch_count <= MAX_BATCH_COUNT);
13	    Q.resize(n);
14	  }
15	
16	  const static int kappa = SEC_P_COM;
17	  // Upper bound to prevent integer-overflow and unbounded memory allocation when `n` is untrusted.
18	  // This is a defensive limit; callers should treat any larger batch as invalid input.
19	  static constexpr int MAX_BATCH_COUNT = 100000;
20	  // We assume the base encryption scheme requires 32 bytes of randomness. If it needs more, it can be changed to use
21	  // DRBG with 32 bytes of randomness as the seed.
22	  const static int rho_size = 32;
23	
24	  /**
25	   * @specs:
26	   * - publicly-verifiable-encryption-spec | vencrypt-batch-1P
27	   */
28	  error_t encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve,
29	                  const std::vector<bn_t>& x);
30	
31	  /**
32	   * @specs:
33	   * - publicly-verifiable-encryption-spec | vverify-batch-1P
34	   */
35	  error_t verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const std::vector<ecc_point_t>& Q, mem_t label) const;
36	
37	  /**
38	   * @specs:
39	   * - publicly-verifiable-encryption-spec | vdecrypt-batch-1P
40	   */
41	  error_t decrypt(const pve_base_pke_i& base_pke, pve_keyref_t dk, pve_keyref_t ek, mem_t label, ecurve_t curve,
42	                  std::vector<bn_t>& x, bool skip_verify = false) const;
43	
44	  int batch_count() const { return n; }
45	  const std::vector<ecc_point_t>& get_Qs() const { return Q; }
46	  const buf_t& get_Label() const { return L; }
47	
48	  void convert(coinbase::converter_t& converter) {
49	    if (int(Q.size()) != n) {
50	      converter.set_error();
51	      return;
52	    }
53	
54	    converter.convert(Q, L, b);
55	
56	    for (int i = 0; i < kappa; i++) {
57	      converter.convert(rows[i].x_bin);
58	      converter.convert(rows[i].r);
59	      converter.convert(rows[i].c);
60	    }
61	  }
62	
63	 private:
64	  int n;
65	
66	  buf_t L;
67	  std::vector<ecc_point_t> Q;
68	  buf128_t b;
69	
70	  struct row_t {
71	    buf_t x_bin;
72	    buf_t r;
73	    buf_t c;
74	  };
75	  std::vector<row_t> rows;
76	
77	  error_t restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve, std::vector<bn_t>& xs) const;
78	};
