234	template <typename... ARGS>
235	buf_t ser(const ARGS&... args) {
236	  int n;
237	  {
238	    converter_t converter(true);
239	    converter.convert((ARGS&)args...);
240	    n = converter.get_offset();
241	  }
242	
243	  buf_t out(n);
244	
245	  {
246	    converter_t converter(out.data());
247	    converter.convert((ARGS&)args...);
248	  }
249	
250	  return out;
251	}
