220	void converter_t::convert(std::vector<bool>& value) {
221	  if (!write) value.clear();
222	
223	  short count = (short)value.size();
224	  convert(count);
225	
226	  if (!write) {
227	    if (count < 0 || static_cast<uint32_t>(count) > MAX_CONTAINER_ELEMENTS) {
228	      set_error();
229	      return;
230	    }
231	    value.resize(count);
232	  }
233	  for (short i = 0; i < count && !is_error(); i++) {
234	    bool v = value[i];
235	    convert(v);
236	    value[i] = v;
237	  }
238	}
